{
  "name": "MockConnect - Networking Simulator",
  "description": "A risk-free, AI-driven networking simulation environment for job seekers to practice pitches, debug conversation skills, and improve referral conversion rates.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppState {
  DASHBOARD = 'DASHBOARD',
  SETUP = 'SETUP',
  SIMULATION = 'SIMULATION',
  FEEDBACK = 'FEEDBACK'
}

export interface TargetPersona {
  name: string;
  role: string;
  background: string;
  personality: string;
  company: string;
}

export interface SessionData {
  targetProfile: string;
  jobDescription: string;
  persona?: TargetPersona;
  previousFeedback?: FeedbackData;
}

export interface FeedbackData {
  score: number;
  strengths: string[];
  weaknesses: string[];
  suggestions: string[];
  conversationSummary: string;
  difficultyAdjustment: string;
}

export interface MessageLog {
  role: 'user' | 'model';
  text: string;
}

import React, { useState, useCallback } from 'react';
import { Dashboard } from './components/Dashboard';
import { Setup } from './components/Setup';
import { Simulation } from './components/Simulation';
import { Feedback } from './components/Feedback';
import { AppState, SessionData, FeedbackData, MessageLog } from './types';

const App: React.FC = () => {
  const [currentState, setCurrentState] = useState<AppState>(AppState.DASHBOARD);
  const [session, setSession] = useState<SessionData>({
    targetProfile: '',
    jobDescription: '',
  });
  const [lastMessages, setLastMessages] = useState<MessageLog[]>([]);
  const [feedback, setFeedback] = useState<FeedbackData | null>(null);

  const startSetup = () => setCurrentState(AppState.SETUP);

  const handleSetupComplete = (data: Partial<SessionData>) => {
    setSession(prev => ({ ...prev, ...data }));
    setCurrentState(AppState.SIMULATION);
  };

  const handleSimulationEnd = (messages: MessageLog[], generatedFeedback: FeedbackData) => {
    setLastMessages(messages);
    setFeedback(generatedFeedback);
    setCurrentState(AppState.FEEDBACK);
  };

  const handleRetry = () => {
    // Adaptive retry logic: update session with previous feedback
    if (feedback) {
      setSession(prev => ({
        ...prev,
        previousFeedback: feedback
      }));
    }
    setCurrentState(AppState.SIMULATION);
  };

  const resetToDashboard = () => {
    setSession({ targetProfile: '', jobDescription: '' });
    setFeedback(null);
    setLastMessages([]);
    setCurrentState(AppState.DASHBOARD);
  };

  return (
    <div className="min-h-screen flex flex-col">
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex justify-between items-center sticky top-0 z-50">
        <div className="flex items-center space-x-2 cursor-pointer" onClick={resetToDashboard}>
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center">
            <span className="text-white font-bold text-xl">M</span>
          </div>
          <h1 className="text-xl font-bold text-slate-800">MockConnect</h1>
        </div>
        <nav className="flex items-center space-x-6">
          <button className="text-slate-600 hover:text-indigo-600 font-medium text-sm transition-colors">Resources</button>
          <button className="text-slate-600 hover:text-indigo-600 font-medium text-sm transition-colors">History</button>
          <button className="bg-slate-100 hover:bg-slate-200 text-slate-800 px-4 py-2 rounded-full text-sm font-semibold transition-all">Sign In</button>
        </nav>
      </header>

      <main className="flex-grow">
        {currentState === AppState.DASHBOARD && <Dashboard onStart={startSetup} />}
        {currentState === AppState.SETUP && <Setup onComplete={handleSetupComplete} />}
        {currentState === AppState.SIMULATION && (
          <Simulation 
            session={session} 
            onEnd={handleSimulationEnd} 
            onCancel={resetToDashboard}
          />
        )}
        {currentState === AppState.FEEDBACK && feedback && (
          <Feedback 
            feedback={feedback} 
            onRetry={handleRetry} 
            onDone={resetToDashboard} 
          />
        )}
      </main>

      <footer className="bg-slate-50 border-t border-slate-200 py-8 px-6">
        <div className="max-w-6xl mx-auto flex flex-col md:flex-row justify-between items-center text-slate-500 text-sm">
          <p>© 2024 MockConnect. Designed for introverts and non-native speakers.</p>
          <div className="flex space-x-4 mt-4 md:mt-0">
            <a href="#" className="hover:text-indigo-600 transition-colors">Privacy</a>
            <a href="#" className="hover:text-indigo-600 transition-colors">Terms</a>
            <a href="#" className="hover:text-indigo-600 transition-colors">Help</a>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { TargetPersona } from '../types';
import { GoogleGenAI, Type } from "@google/genai";

interface SetupProps {
  onComplete: (data: { targetProfile: string, jobDescription: string, persona: TargetPersona }) => void;
}

export const Setup: React.FC<SetupProps> = ({ onComplete }) => {
  const [profile, setProfile] = useState('');
  const [jd, setJd] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!profile || !jd) return;

    setIsGenerating(true);
    try {
      // Use Gemini to extract persona data from the input
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Create a professional networking persona based on this info:
          Profile/Website: ${profile}
          Target Job Description: ${jd}`,
        config: {
          responseMimeType: 'application/json',
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              role: { type: Type.STRING },
              background: { type: Type.STRING },
              personality: { type: Type.STRING },
              company: { type: Type.STRING }
            },
            required: ['name', 'role', 'background', 'personality', 'company']
          }
        }
      });

      const persona: TargetPersona = JSON.parse(response.text || '{}');
      onComplete({ targetProfile: profile, jobDescription: jd, persona });
    } catch (error) {
      console.error("Error generating persona:", error);
      // Fallback persona if AI fails
      onComplete({ 
        targetProfile: profile, 
        jobDescription: jd, 
        persona: {
          name: "Alex Rivera",
          role: "Senior Engineering Manager",
          background: "15 years in tech, former software architect at Google.",
          personality: "Direct, analytical, values brevity but appreciates well-researched questions.",
          company: "InnovateTech"
        } 
      });
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto px-6 py-12">
      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm p-8 md:p-12">
        <h2 className="text-3xl font-bold text-slate-900 mb-2">Configure Your Simulation</h2>
        <p className="text-slate-500 mb-10">Paste the details of who you're networking with and the role you want.</p>

        <form onSubmit={handleSubmit} className="space-y-8">
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-3">
              LinkedIn Profile or Website Text
            </label>
            <textarea 
              value={profile}
              onChange={(e) => setProfile(e.target.value)}
              placeholder="Paste LinkedIn summary, experience details, or a link..."
              className="w-full h-32 p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
              required
            />
          </div>

          <div>
            <label className="block text-sm font-bold text-slate-700 mb-3">
              Target Job Description
            </label>
            <textarea 
              value={jd}
              onChange={(e) => setJd(e.target.value)}
              placeholder="Paste the job description you are targeting..."
              className="w-full h-32 p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
              required
            />
          </div>

          <div className="pt-4">
            <button 
              type="submit"
              disabled={isGenerating || !profile || !jd}
              className={`w-full py-4 rounded-xl font-bold text-white transition-all shadow-lg ${
                isGenerating ? 'bg-indigo-400 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700'
              }`}
            >
              {isGenerating ? (
                <span className="flex items-center justify-center">
                  <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Generating AI Persona...
                </span>
              ) : 'Ready Your Agent'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { SessionData, MessageLog, FeedbackData } from '../types';
import { Type } from "@google/genai";

interface SimulationProps {
  session: SessionData;
  onEnd: (messages: MessageLog[], feedback: FeedbackData) => void;
  onCancel: () => void;
}

export const Simulation: React.FC<SimulationProps> = ({ session, onEnd, onCancel }) => {
  const [isActive, setIsActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [messages, setMessages] = useState<MessageLog[]>([]);
  const [isEnding, setIsEnding] = useState(false);
  const [timer, setTimer] = useState(300); // 5 minutes

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const transcriptionRef = useRef({ user: '', model: '' });

  // Audio encoding/decoding helpers
  const encode = (bytes: Uint8Array) => {
    let binary = '';
    for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
    return btoa(binary);
  };
  const decode = (base64: string) => {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
    return bytes;
  };
  const decodeAudioData = async (data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number) => {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
    return buffer;
  };

  const startSimulation = async () => {
    setIsConnecting(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true, video: true });
      if (videoRef.current) videoRef.current.srcObject = stream;

      const inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const systemInstruction = `
        You are simulating a networking conversation. 
        Persona Name: ${session.persona?.name}
        Role: ${session.persona?.role} at ${session.persona?.company}
        Background: ${session.persona?.background}
        Personality Style: ${session.persona?.personality}
        Target Job Context: ${session.jobDescription}

        ${session.previousFeedback ? `The user is retrying this scenario. Previous feedback was: ${JSON.stringify(session.previousFeedback)}. Focus on challenging them on their weaknesses.` : ''}

        Rules:
        - Act as this person naturally. 
        - Start by acknowledging the user's opening pitch.
        - Ask insightful follow-up questions.
        - Be realistic. If the pitch is poor, be politely skeptical.
        - Goal: Help the user practice until they are ready for a referral.
      `;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsActive(true);
            setIsConnecting(false);

            // Microphone stream
            const source = inputAudioContext.createMediaStreamSource(stream);
            const scriptProcessor = inputAudioContext.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000'
              };
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inputAudioContext.destination);

            // Frame stream (Visual context)
            const interval = setInterval(() => {
              if (!videoRef.current || !canvasRef.current) return;
              const ctx = canvasRef.current.getContext('2d');
              if (!ctx) return;
              canvasRef.current.width = 320;
              canvasRef.current.height = 240;
              ctx.drawImage(videoRef.current, 0, 0, 320, 240);
              canvasRef.current.toBlob(blob => {
                if (blob) {
                  const reader = new FileReader();
                  reader.onloadend = () => {
                    const base64 = (reader.result as string).split(',')[1];
                    sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'image/jpeg' } }));
                  };
                  reader.readAsDataURL(blob);
                }
              }, 'image/jpeg', 0.5);
            }, 1000);
            (sessionRef as any).currentInterval = interval;
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle audio output
            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && outputAudioContextRef.current) {
              const buffer = await decodeAudioData(decode(audioData), outputAudioContextRef.current, 24000, 1);
              const source = outputAudioContextRef.current.createBufferSource();
              source.buffer = buffer;
              source.connect(outputAudioContextRef.current.destination);
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioContextRef.current.currentTime);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              source.onended = () => sourcesRef.current.delete(source);
            }

            // Handle Transcriptions for feedback step
            if (message.serverContent?.inputTranscription) {
              transcriptionRef.current.user += message.serverContent.inputTranscription.text + " ";
            }
            if (message.serverContent?.outputTranscription) {
              transcriptionRef.current.model += message.serverContent.outputTranscription.text + " ";
            }
            if (message.serverContent?.turnComplete) {
              setMessages(prev => [
                ...prev,
                { role: 'user', text: transcriptionRef.current.user },
                { role: 'model', text: transcriptionRef.current.model }
              ]);
              transcriptionRef.current = { user: '', model: '' };
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e) => console.error("Session Error:", e),
          onclose: () => setIsActive(false),
        },
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction,
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error(err);
      setIsConnecting(false);
    }
  };

  useEffect(() => {
    let interval: any;
    if (isActive && timer > 0) {
      interval = setInterval(() => setTimer(t => t - 1), 1000);
    } else if (timer === 0 && isActive) {
      endSession();
    }
    return () => clearInterval(interval);
  }, [isActive, timer]);

  const endSession = async () => {
    if (isEnding) return;
    setIsEnding(true);

    // Stop recording/streaming
    if (sessionRef.current) {
      clearInterval(sessionRef.current.currentInterval);
      sessionRef.current.close();
    }

    // Process final feedback using Gemini Chat
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const conversationText = messages.map(m => `${m.role}: ${m.text}`).join('\n');

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Evaluate this networking simulation for a job seeker. 
          Target Role: ${session.persona?.role}
          Job: ${session.jobDescription}
          Conversation:
          ${conversationText}`,
        config: {
          responseMimeType: 'application/json',
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              score: { type: Type.NUMBER, description: 'Score from 0 to 100' },
              strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
              weaknesses: { type: Type.ARRAY, items: { type: Type.STRING } },
              suggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
              conversationSummary: { type: Type.STRING },
              difficultyAdjustment: { type: Type.STRING, description: 'How to adjust difficulty for next time' }
            },
            required: ['score', 'strengths', 'weaknesses', 'suggestions', 'conversationSummary', 'difficultyAdjustment']
          }
        }
      });

      const feedback: FeedbackData = JSON.parse(response.text || '{}');
      onEnd(messages, feedback);
    } catch (err) {
      console.error("Failed to generate feedback:", err);
      // Fallback feedback
      onEnd(messages, {
        score: 75,
        strengths: ["Clear opening pitch", "Good enthusiasm"],
        weaknesses: ["Too focused on self", "Lack of research on company"],
        suggestions: ["Ask more about the persona's recent work", "Keep answers under 60 seconds"],
        conversationSummary: "You had a standard interaction but failed to bridge to a referral request.",
        difficultyAdjustment: "Increase skepticisms of the persona"
      });
    }
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  return (
    <div className="fixed inset-0 bg-slate-900 z-[100] flex flex-col items-center justify-center overflow-hidden">
      {!isActive && !isConnecting && (
        <div className="text-center p-8 max-w-xl">
          <h2 className="text-3xl font-bold text-white mb-6">Simulation Ready</h2>
          <p className="text-slate-400 mb-10">
            You will be speaking with <strong>{session.persona?.name}</strong>. 
            Prepare your opening pitch. Camera is recommended for visual feedback but optional.
          </p>
          <div className="flex space-x-4 justify-center">
            <button 
              onClick={startSimulation}
              className="px-10 py-4 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl shadow-xl transition-all"
            >
              Enter Room
            </button>
            <button 
              onClick={onCancel}
              className="px-10 py-4 bg-slate-800 hover:bg-slate-700 text-white font-bold rounded-xl transition-all"
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      {(isActive || isConnecting) && (
        <div className="w-full h-full flex flex-col">
          {/* Header Info */}
          <div className="p-6 flex justify-between items-center text-white bg-slate-900/50 backdrop-blur-md">
            <div className="flex items-center space-x-4">
              <div className="w-12 h-12 rounded-full overflow-hidden border-2 border-indigo-500">
                <img src={`https://picsum.photos/seed/${session.persona?.name}/48/48`} alt="Persona" />
              </div>
              <div>
                <h3 className="font-bold text-lg">{session.persona?.name}</h3>
                <p className="text-xs text-slate-400 uppercase tracking-widest">{session.persona?.role}</p>
              </div>
            </div>
            <div className="flex items-center space-x-6">
              <div className="text-center">
                <p className="text-xs text-slate-500 uppercase font-bold">Time Left</p>
                <p className={`text-xl font-mono ${timer < 60 ? 'text-red-500 animate-pulse' : 'text-white'}`}>{formatTime(timer)}</p>
              </div>
              <button 
                onClick={endSession}
                className="px-6 py-2 bg-red-600 hover:bg-red-700 text-white font-bold rounded-lg transition-all"
                disabled={isEnding}
              >
                {isEnding ? 'Processing...' : 'End Session'}
              </button>
            </div>
          </div>

          {/* Main Visual Area */}
          <div className="flex-grow flex flex-col md:flex-row p-6 gap-6 relative">
            {/* The "Persona" Card */}
            <div className="flex-grow bg-slate-800 rounded-3xl overflow-hidden border border-slate-700 flex flex-col items-center justify-center relative shadow-2xl">
              <div className="absolute inset-0 opacity-20 pointer-events-none">
                <div className="w-full h-full bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-indigo-500/20 via-transparent to-transparent animate-pulse"></div>
              </div>

              <div className="z-10 text-center">
                <div className="w-32 h-32 rounded-full bg-slate-700 mx-auto mb-6 flex items-center justify-center border-4 border-indigo-500/30 overflow-hidden">
                   {isActive ? (
                     <div className="flex space-x-1 items-end h-8">
                       {[1, 2, 3, 4, 5].map(i => (
                         <div key={i} className={`w-1.5 bg-indigo-400 rounded-full animate-bounce`} style={{ animationDelay: `${i * 0.1}s`, height: `${Math.random() * 100 + 20}%` }}></div>
                       ))}
                     </div>
                   ) : (
                     <div className="text-slate-500">Connecting...</div>
                   )}
                </div>
                <h2 className="text-2xl font-bold text-white mb-2">{isConnecting ? 'Establishing Connection...' : 'AI Participant Listening...'}</h2>
                <p className="text-indigo-400 font-medium">Speak naturally to begin your pitch</p>
              </div>
            </div>

            {/* Camera Feed (User) */}
            <div className="w-full md:w-80 h-60 md:h-auto bg-black rounded-3xl overflow-hidden border border-slate-700 shadow-2xl relative">
              <video 
                ref={videoRef} 
                autoPlay 
                muted 
                playsInline 
                className="w-full h-full object-cover mirror"
              />
              <canvas ref={canvasRef} className="hidden" />
              <div className="absolute bottom-4 left-4 right-4 bg-black/40 backdrop-blur-sm p-3 rounded-xl border border-white/10">
                <div className="flex items-center space-x-2">
                  <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
                  <span className="text-xs text-white font-bold uppercase">Microphone Active</span>
                </div>
              </div>
            </div>
          </div>

          {/* Chat Preview footer */}
          <div className="h-24 bg-slate-800/80 border-t border-slate-700 p-4 flex items-center justify-center">
            <div className="max-w-2xl w-full text-center">
               <p className="text-slate-400 italic text-sm">
                 {messages.length > 0 ? messages[messages.length - 1].text.substring(0, 100) + "..." : "Transcribing in real-time..."}
               </p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { SessionData, MessageLog, FeedbackData } from '../types';
import { Type } from "@google/genai";

interface SimulationProps {
  session: SessionData;
  onEnd: (messages: MessageLog[], feedback: FeedbackData) => void;
  onCancel: () => void;
}

export const Simulation: React.FC<SimulationProps> = ({ session, onEnd, onCancel }) => {
  const [isActive, setIsActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [messages, setMessages] = useState<MessageLog[]>([]);
  const [isEnding, setIsEnding] = useState(false);
  const [timer, setTimer] = useState(300); // 5 minutes

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const transcriptionRef = useRef({ user: '', model: '' });

  // Audio encoding/decoding helpers
  const encode = (bytes: Uint8Array) => {
    let binary = '';
    for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
    return btoa(binary);
  };
  const decode = (base64: string) => {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
    return bytes;
  };
  const decodeAudioData = async (data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number) => {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
    return buffer;
  };

  const startSimulation = async () => {
    setIsConnecting(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true, video: true });
      if (videoRef.current) videoRef.current.srcObject = stream;

      const inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const systemInstruction = `
        You are simulating a networking conversation. 
        Persona Name: ${session.persona?.name}
        Role: ${session.persona?.role} at ${session.persona?.company}
        Background: ${session.persona?.background}
        Personality Style: ${session.persona?.personality}
        Target Job Context: ${session.jobDescription}

        ${session.previousFeedback ? `The user is retrying this scenario. Previous feedback was: ${JSON.stringify(session.previousFeedback)}. Focus on challenging them on their weaknesses.` : ''}

        Rules:
        - MANDATORY START: You MUST initiate the conversation. Do not wait for the user to speak first.
        - Immediately introduce yourself as ${session.persona?.name} and mention your role.
        - Set a professional but welcoming tone. Say something like: "Hello! I'm ${session.persona?.name}, ${session.persona?.role}. I saw your request to connect regarding the ${session.jobDescription.split(' ').slice(0, 5).join(' ')}... context. Glad we could find a moment. What's on your mind?"
        - Act as this person naturally. 
        - Ask insightful follow-up questions.
        - Be realistic. If the pitch is poor, be politely skeptical.
        - Goal: Help the user practice until they are ready for a referral.
      `;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsActive(true);
            setIsConnecting(false);

            // Microphone stream
            const source = inputAudioContext.createMediaStreamSource(stream);
            const scriptProcessor = inputAudioContext.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000'
              };
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inputAudioContext.destination);

            // Frame stream (Visual context)
            const frameInterval = setInterval(() => {
              if (!videoRef.current || !canvasRef.current) return;
              const ctx = canvasRef.current.getContext('2d');
              if (!ctx) return;
              canvasRef.current.width = 320;
              canvasRef.current.height = 240;
              ctx.drawImage(videoRef.current, 0, 0, 320, 240);
              canvasRef.current.toBlob(blob => {
                if (blob) {
                  const reader = new FileReader();
                  reader.onloadend = () => {
                    const base64 = (reader.result as string).split(',')[1];
                    sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'image/jpeg' } }));
                  };
                  reader.readAsDataURL(blob);
                }
              }, 'image/jpeg', 0.5);
            }, 1000);
            (sessionRef as any).currentInterval = frameInterval;

            // CRITICAL: Trigger the model to introduce itself first
            sessionPromise.then(s => {
              s.sendRealtimeInput({ 
                text: "The user has joined the meeting. Please start the conversation by introducing yourself and welcoming the user." 
              });
            });
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle audio output
            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && outputAudioContextRef.current) {
              const buffer = await decodeAudioData(decode(audioData), outputAudioContextRef.current, 24000, 1);
              const source = outputAudioContextRef.current.createBufferSource();
              source.buffer = buffer;
              source.connect(outputAudioContextRef.current.destination);
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioContextRef.current.currentTime);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              source.onended = () => sourcesRef.current.delete(source);
            }

            // Handle Transcriptions for feedback step
            if (message.serverContent?.inputTranscription) {
              transcriptionRef.current.user += message.serverContent.inputTranscription.text + " ";
            }
            if (message.serverContent?.outputTranscription) {
              transcriptionRef.current.model += message.serverContent.outputTranscription.text + " ";
            }
            if (message.serverContent?.turnComplete) {
              const uText = transcriptionRef.current.user.trim();
              const mText = transcriptionRef.current.model.trim();
              if (uText || mText) {
                setMessages(prev => [
                  ...prev,
                  { role: 'user', text: uText || "(Silent Listening)" },
                  { role: 'model', text: mText }
                ]);
              }
              transcriptionRef.current = { user: '', model: '' };
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e) => console.error("Session Error:", e),
          onclose: () => setIsActive(false),
        },
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction,
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error(err);
      setIsConnecting(false);
    }
  };

  useEffect(() => {
    let interval: any;
    if (isActive && timer > 0) {
      interval = setInterval(() => setTimer(t => t - 1), 1000);
    } else if (timer === 0 && isActive) {
      endSession();
    }
    return () => clearInterval(interval);
  }, [isActive, timer]);

  const endSession = async () => {
    if (isEnding) return;
    setIsEnding(true);

    // Stop recording/streaming
    if (sessionRef.current) {
      if ((sessionRef as any).currentInterval) clearInterval((sessionRef as any).currentInterval);
      sessionRef.current.close();
    }

    // Process final feedback using Gemini Chat
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const conversationText = messages.map(m => `${m.role}: ${m.text}`).join('\n');

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Evaluate this networking simulation for a job seeker. 
          Target Role: ${session.persona?.role}
          Job: ${session.jobDescription}
          Conversation:
          ${conversationText}`,
        config: {
          responseMimeType: 'application/json',
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              score: { type: Type.NUMBER, description: 'Score from 0 to 100' },
              strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
              weaknesses: { type: Type.ARRAY, items: { type: Type.STRING } },
              suggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
              conversationSummary: { type: Type.STRING },
              difficultyAdjustment: { type: Type.STRING, description: 'How to adjust difficulty for next time' }
            },
            required: ['score', 'strengths', 'weaknesses', 'suggestions', 'conversationSummary', 'difficultyAdjustment']
          }
        }
      });

      const feedback: FeedbackData = JSON.parse(response.text || '{}');
      onEnd(messages, feedback);
    } catch (err) {
      console.error("Failed to generate feedback:", err);
      // Fallback feedback
      onEnd(messages, {
        score: 75,
        strengths: ["Clear opening pitch", "Good enthusiasm"],
        weaknesses: ["Too focused on self", "Lack of research on company"],
        suggestions: ["Ask more about the persona's recent work", "Keep answers under 60 seconds"],
        conversationSummary: "You had a standard interaction but failed to bridge to a referral request.",
        difficultyAdjustment: "Increase skepticisms of the persona"
      });
    }
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  return (
    <div className="fixed inset-0 bg-slate-900 z-[100] flex flex-col items-center justify-center overflow-hidden">
      {!isActive && !isConnecting && (
        <div className="text-center p-8 max-w-xl">
          <h2 className="text-3xl font-bold text-white mb-6">Simulation Ready</h2>
          <p className="text-slate-400 mb-10">
            You will be speaking with <strong>{session.persona?.name}</strong>. 
            Once you enter, <strong>they will introduce themselves first</strong>. Listen carefully and then respond with your pitch.
          </p>
          <div className="flex space-x-4 justify-center">
            <button 
              onClick={startSimulation}
              className="px-10 py-4 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl shadow-xl transition-all"
            >
              Enter Room
            </button>
            <button 
              onClick={onCancel}
              className="px-10 py-4 bg-slate-800 hover:bg-slate-700 text-white font-bold rounded-xl transition-all"
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      {(isActive || isConnecting) && (
        <div className="w-full h-full flex flex-col">
          {/* Header Info */}
          <div className="p-6 flex justify-between items-center text-white bg-slate-900/50 backdrop-blur-md">
            <div className="flex items-center space-x-4">
              <div className="w-12 h-12 rounded-full overflow-hidden border-2 border-indigo-500">
                <img src={`https://picsum.photos/seed/${session.persona?.name}/48/48`} alt="Persona" />
              </div>
              <div>
                <h3 className="font-bold text-lg">{session.persona?.name}</h3>
                <p className="text-xs text-slate-400 uppercase tracking-widest">{session.persona?.role}</p>
              </div>
            </div>
            <div className="flex items-center space-x-6">
              <div className="text-center">
                <p className="text-xs text-slate-500 uppercase font-bold">Time Left</p>
                <p className={`text-xl font-mono ${timer < 60 ? 'text-red-500 animate-pulse' : 'text-white'}`}>{formatTime(timer)}</p>
              </div>
              <button 
                onClick={endSession}
                className="px-6 py-2 bg-red-600 hover:bg-red-700 text-white font-bold rounded-lg transition-all"
                disabled={isEnding}
              >
                {isEnding ? 'Processing...' : 'End Session'}
              </button>
            </div>
          </div>

          {/* Main Visual Area */}
          <div className="flex-grow flex flex-col md:flex-row p-6 gap-6 relative">
            {/* The "Persona" Card */}
            <div className="flex-grow bg-slate-800 rounded-3xl overflow-hidden border border-slate-700 flex flex-col items-center justify-center relative shadow-2xl">
              <div className="absolute inset-0 opacity-20 pointer-events-none">
                <div className="w-full h-full bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-indigo-500/20 via-transparent to-transparent animate-pulse"></div>
              </div>

              <div className="z-10 text-center">
                <div className="w-32 h-32 rounded-full bg-slate-700 mx-auto mb-6 flex items-center justify-center border-4 border-indigo-500/30 overflow-hidden">
                   {isActive ? (
                     <div className="flex space-x-1 items-end h-8">
                       {[1, 2, 3, 4, 5].map(i => (
                         <div key={i} className={`w-1.5 bg-indigo-400 rounded-full animate-bounce`} style={{ animationDelay: `${i * 0.1}s`, height: `${Math.random() * 100 + 20}%` }}></div>
                       ))}
                     </div>
                   ) : (
                     <div className="text-slate-500">Connecting...</div>
                   )}
                </div>
                <h2 className="text-2xl font-bold text-white mb-2">
                  {isConnecting ? 'Establishing Connection...' : `${session.persona?.name} is Speaking...`}
                </h2>
                <p className="text-indigo-400 font-medium">Listen to the introduction</p>
              </div>
            </div>

            {/* Camera Feed (User) */}
            <div className="w-full md:w-80 h-60 md:h-auto bg-black rounded-3xl overflow-hidden border border-slate-700 shadow-2xl relative">
              <video 
                ref={videoRef} 
                autoPlay 
                muted 
                playsInline 
                className="w-full h-full object-cover mirror"
              />
              <canvas ref={canvasRef} className="hidden" />
              <div className="absolute bottom-4 left-4 right-4 bg-black/40 backdrop-blur-sm p-3 rounded-xl border border-white/10">
                <div className="flex items-center space-x-2">
                  <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
                  <span className="text-xs text-white font-bold uppercase">Microphone Active</span>
                </div>
              </div>
            </div>
          </div>

          {/* Chat Preview footer */}
          <div className="h-24 bg-slate-800/80 border-t border-slate-700 p-4 flex items-center justify-center">
            <div className="max-w-2xl w-full text-center">
               <p className="text-slate-400 italic text-sm">
                 {messages.length > 0 ? messages[messages.length - 1].text.substring(0, 100) + "..." : "Transcribing interaction..."}
               </p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { SessionData, MessageLog, FeedbackData } from '../types';
import { Type } from "@google/genai";

interface SimulationProps {
  session: SessionData;
  onEnd: (messages: MessageLog[], feedback: FeedbackData) => void;
  onCancel: () => void;
}

export const Simulation: React.FC<SimulationProps> = ({ session, onEnd, onCancel }) => {
  const [isActive, setIsActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [messages, setMessages] = useState<MessageLog[]>([]);
  const [isEnding, setIsEnding] = useState(false);
  const [timer, setTimer] = useState(300); // 5 minutes

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const transcriptionRef = useRef({ user: '', model: '' });

  // Audio encoding/decoding helpers
  const encode = (bytes: Uint8Array) => {
    let binary = '';
    for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
    return btoa(binary);
  };
  const decode = (base64: string) => {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
    return bytes;
  };
  const decodeAudioData = async (data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number) => {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
    return buffer;
  };

  const startSimulation = async () => {
    setIsConnecting(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true, video: true });
      if (videoRef.current) videoRef.current.srcObject = stream;

      const inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const systemInstruction = `
        You are simulating a networking conversation. 
        Persona Name: ${session.persona?.name}
        Role: ${session.persona?.role} at ${session.persona?.company}
        Background: ${session.persona?.background}
        Personality Style: ${session.persona?.personality}
        Target Job Context: ${session.jobDescription}

        ${session.previousFeedback ? `The user is retrying this scenario. Previous feedback was: ${JSON.stringify(session.previousFeedback)}. Focus on challenging them on their weaknesses.` : ''}

        Rules:
        - MANDATORY START: You MUST initiate the conversation. Do not wait for the user to speak first.
        - Immediately introduce yourself as ${session.persona?.name} and mention your role.
        - Set a professional but welcoming tone. Say something like: "Hello! I'm ${session.persona?.name}, ${session.persona?.role}. I saw your request to connect regarding the ${session.jobDescription.split(' ').slice(0, 5).join(' ')}... context. Glad we could find a moment. What's on your mind?"
        - Act as this person naturally. 
        - Ask insightful follow-up questions.
        - Be realistic. If the pitch is poor, be politely skeptical.
        - Goal: Help the user practice until they are ready for a referral.
      `;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsActive(true);
            setIsConnecting(false);

            // Microphone stream
            const source = inputAudioContext.createMediaStreamSource(stream);
            const scriptProcessor = inputAudioContext.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000'
              };
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inputAudioContext.destination);

            // Frame stream (Visual context)
            const frameInterval = setInterval(() => {
              if (!videoRef.current || !canvasRef.current) return;
              const ctx = canvasRef.current.getContext('2d');
              if (!ctx) return;
              canvasRef.current.width = 320;
              canvasRef.current.height = 240;
              ctx.drawImage(videoRef.current, 0, 0, 320, 240);
              canvasRef.current.toBlob(blob => {
                if (blob) {
                  const reader = new FileReader();
                  reader.onloadend = () => {
                    const base64 = (reader.result as string).split(',')[1];
                    sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'image/jpeg' } }));
                  };
                  reader.readAsDataURL(blob);
                }
              }, 'image/jpeg', 0.5);
            }, 1000);
            (sessionRef as any).currentInterval = frameInterval;

            // CRITICAL: Trigger the model to introduce itself first
            sessionPromise.then(s => {
              s.sendRealtimeInput({ 
                text: "The user has joined the meeting. Please start the conversation by introducing yourself and welcoming the user." 
              });
            });
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle audio output
            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && outputAudioContextRef.current) {
              const buffer = await decodeAudioData(decode(audioData), outputAudioContextRef.current, 24000, 1);
              const source = outputAudioContextRef.current.createBufferSource();
              source.buffer = buffer;
              source.connect(outputAudioContextRef.current.destination);
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioContextRef.current.currentTime);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              source.onended = () => sourcesRef.current.delete(source);
            }

            // Handle Transcriptions for feedback step
            if (message.serverContent?.inputTranscription) {
              transcriptionRef.current.user += message.serverContent.inputTranscription.text + " ";
            }
            if (message.serverContent?.outputTranscription) {
              transcriptionRef.current.model += message.serverContent.outputTranscription.text + " ";
            }
            if (message.serverContent?.turnComplete) {
              const uText = transcriptionRef.current.user.trim();
              const mText = transcriptionRef.current.model.trim();
              if (uText || mText) {
                setMessages(prev => [
                  ...prev,
                  { role: 'user', text: uText || "(Silent Listening)" },
                  { role: 'model', text: mText }
                ]);
              }
              transcriptionRef.current = { user: '', model: '' };
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e) => console.error("Session Error:", e),
          onclose: () => setIsActive(false),
        },
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction,
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error(err);
      setIsConnecting(false);
    }
  };

  useEffect(() => {
    let interval: any;
    if (isActive && timer > 0) {
      interval = setInterval(() => setTimer(t => t - 1), 1000);
    } else if (timer === 0 && isActive) {
      endSession();
    }
    return () => clearInterval(interval);
  }, [isActive, timer]);

  const endSession = async () => {
    if (isEnding) return;
    setIsEnding(true);

    // Stop recording/streaming
    if (sessionRef.current) {
      if ((sessionRef as any).currentInterval) clearInterval((sessionRef as any).currentInterval);
      sessionRef.current.close();
    }

    // Process final feedback using Gemini Chat
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const conversationText = messages.map(m => `${m.role}: ${m.text}`).join('\n');

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Evaluate this networking simulation for a job seeker. 
          Target Role: ${session.persona?.role}
          Job: ${session.jobDescription}
          Conversation:
          ${conversationText}`,
        config: {
          responseMimeType: 'application/json',
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              score: { type: Type.NUMBER, description: 'Score from 0 to 100' },
              strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
              weaknesses: { type: Type.ARRAY, items: { type: Type.STRING } },
              suggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
              conversationSummary: { type: Type.STRING },
              difficultyAdjustment: { type: Type.STRING, description: 'How to adjust difficulty for next time' }
            },
            required: ['score', 'strengths', 'weaknesses', 'suggestions', 'conversationSummary', 'difficultyAdjustment']
          }
        }
      });

      const feedback: FeedbackData = JSON.parse(response.text || '{}');
      onEnd(messages, feedback);
    } catch (err) {
      console.error("Failed to generate feedback:", err);
      // Fallback feedback
      onEnd(messages, {
        score: 75,
        strengths: ["Clear opening pitch", "Good enthusiasm"],
        weaknesses: ["Too focused on self", "Lack of research on company"],
        suggestions: ["Ask more about the persona's recent work", "Keep answers under 60 seconds"],
        conversationSummary: "You had a standard interaction but failed to bridge to a referral request.",
        difficultyAdjustment: "Increase skepticisms of the persona"
      });
    }
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  // Dedicated loading UI for the feedback generation phase
  if (isEnding) {
    return (
      <div className="fixed inset-0 bg-slate-900 z-[100] flex flex-col items-center justify-center">
        <div className="text-center p-8 max-w-xl">
          <div className="relative w-24 h-24 mx-auto mb-8">
            <div className="absolute inset-0 border-4 border-indigo-500/20 rounded-full"></div>
            <div className="absolute inset-0 border-4 border-indigo-500 rounded-full border-t-transparent animate-spin"></div>
          </div>
          <h2 className="text-3xl font-bold text-white mb-4">Generating Session Review</h2>
          <p className="text-slate-400">
            Analyzing your conversation with <strong>{session.persona?.name}</strong>...<br/>
            Evaluating clarity, confidence, and impact.
          </p>
          <div className="mt-8 flex justify-center space-x-2">
            <div className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce"></div>
            <div className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce delay-100"></div>
            <div className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce delay-200"></div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 bg-slate-900 z-[100] flex flex-col items-center justify-center overflow-hidden">
      {!isActive && !isConnecting && (
        <div className="text-center p-8 max-w-xl">
          <h2 className="text-3xl font-bold text-white mb-6">Simulation Ready</h2>
          <p className="text-slate-400 mb-10">
            You will be speaking with <strong>{session.persona?.name}</strong>. 
            Once you enter, <strong>they will introduce themselves first</strong>. Listen carefully and then respond with your pitch.
          </p>
          <div className="flex space-x-4 justify-center">
            <button 
              onClick={startSimulation}
              className="px-10 py-4 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl shadow-xl transition-all"
            >
              Enter Room
            </button>
            <button 
              onClick={onCancel}
              className="px-10 py-4 bg-slate-800 hover:bg-slate-700 text-white font-bold rounded-xl transition-all"
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      {(isActive || isConnecting) && (
        <div className="w-full h-full flex flex-col">
          {/* Header Info */}
          <div className="p-6 flex justify-between items-center text-white bg-slate-900/50 backdrop-blur-md">
            <div className="flex items-center space-x-4">
              <div className="w-12 h-12 rounded-full overflow-hidden border-2 border-indigo-500">
                <img src={`https://picsum.photos/seed/${session.persona?.name}/48/48`} alt="Persona" />
              </div>
              <div>
                <h3 className="font-bold text-lg">{session.persona?.name}</h3>
                <p className="text-xs text-slate-400 uppercase tracking-widest">{session.persona?.role}</p>
              </div>
            </div>
            <div className="flex items-center space-x-6">
              <div className="text-center">
                <p className="text-xs text-slate-500 uppercase font-bold">Time Left</p>
                <p className={`text-xl font-mono ${timer < 60 ? 'text-red-500 animate-pulse' : 'text-white'}`}>{formatTime(timer)}</p>
              </div>
              <button 
                onClick={endSession}
                className="px-6 py-2 bg-red-600 hover:bg-red-700 text-white font-bold rounded-lg transition-all"
                disabled={isEnding}
              >
                End Session
              </button>
            </div>
          </div>

          {/* Main Visual Area */}
          <div className="flex-grow flex flex-col md:flex-row p-6 gap-6 relative">
            {/* The "Persona" Card */}
            <div className="flex-grow bg-slate-800 rounded-3xl overflow-hidden border border-slate-700 flex flex-col items-center justify-center relative shadow-2xl">
              <div className="absolute inset-0 opacity-20 pointer-events-none">
                <div className="w-full h-full bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-indigo-500/20 via-transparent to-transparent animate-pulse"></div>
              </div>

              <div className="z-10 text-center">
                <div className="w-32 h-32 rounded-full bg-slate-700 mx-auto mb-6 flex items-center justify-center border-4 border-indigo-500/30 overflow-hidden">
                   {isActive ? (
                     <div className="flex space-x-1 items-end h-8">
                       {[1, 2, 3, 4, 5].map(i => (
                         <div key={i} className={`w-1.5 bg-indigo-400 rounded-full animate-bounce`} style={{ animationDelay: `${i * 0.1}s`, height: `${Math.random() * 100 + 20}%` }}></div>
                       ))}
                     </div>
                   ) : (
                     <div className="text-slate-500">Connecting...</div>
                   )}
                </div>
                <h2 className="text-2xl font-bold text-white mb-2">
                  {isConnecting ? 'Establishing Connection...' : `${session.persona?.name} is Speaking...`}
                </h2>
                <p className="text-indigo-400 font-medium">Listen to the introduction</p>
              </div>
            </div>

            {/* Camera Feed (User) */}
            <div className="w-full md:w-80 h-60 md:h-auto bg-black rounded-3xl overflow-hidden border border-slate-700 shadow-2xl relative">
              <video 
                ref={videoRef} 
                autoPlay 
                muted 
                playsInline 
                className="w-full h-full object-cover mirror"
              />
              <canvas ref={canvasRef} className="hidden" />
              <div className="absolute bottom-4 left-4 right-4 bg-black/40 backdrop-blur-sm p-3 rounded-xl border border-white/10">
                <div className="flex items-center space-x-2">
                  <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
                  <span className="text-xs text-white font-bold uppercase">Microphone Active</span>
                </div>
              </div>
            </div>
          </div>

          {/* Chat Preview footer */}
          <div className="h-24 bg-slate-800/80 border-t border-slate-700 p-4 flex items-center justify-center">
            <div className="max-w-2xl w-full text-center">
               <p className="text-slate-400 italic text-sm">
                 {messages.length > 0 ? messages[messages.length - 1].text.substring(0, 100) + "..." : "Transcribing interaction..."}
               </p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export enum AppState {
  DASHBOARD = 'DASHBOARD',
  SETUP = 'SETUP',
  SIMULATION = 'SIMULATION',
  FEEDBACK = 'FEEDBACK'
}

export interface TargetPersona {
  name: string;
  role: string;
  background: string;
  personality: string;
  company: string;
  voiceType: 'masculine' | 'feminine';
}

export interface SessionData {
  targetProfile: string;
  jobDescription: string;
  persona?: TargetPersona;
  previousFeedback?: FeedbackData;
}

export interface FeedbackData {
  score: number;
  strengths: string[];
  weaknesses: string[];
  suggestions: string[];
  conversationSummary: string;
  difficultyAdjustment: string;
}

export interface MessageLog {
  role: 'user' | 'model';
  text: string;
}

import React, { useState } from 'react';
import { TargetPersona } from '../types';
import { GoogleGenAI, Type } from "@google/genai";

interface SetupProps {
  onComplete: (data: { targetProfile: string, jobDescription: string, persona: TargetPersona }) => void;
}

export const Setup: React.FC<SetupProps> = ({ onComplete }) => {
  const [profile, setProfile] = useState('');
  const [jd, setJd] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!profile || !jd) return;

    setIsGenerating(true);
    try {
      // Use Gemini to extract persona data from the input
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Create a professional networking persona based on this info:
          Profile/Website: ${profile}
          Target Job Description: ${jd}

          Based on the profile details, identify the gender of the person to select a masculine or feminine voice for the simulation.`,
        config: {
          responseMimeType: 'application/json',
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              role: { type: Type.STRING },
              background: { type: Type.STRING },
              personality: { type: Type.STRING },
              company: { type: Type.STRING },
              voiceType: { 
                type: Type.STRING, 
                enum: ['masculine', 'feminine'],
                description: 'The appropriate voice type based on the profile gender/name' 
              }
            },
            required: ['name', 'role', 'background', 'personality', 'company', 'voiceType']
          }
        }
      });

      const persona: TargetPersona = JSON.parse(response.text || '{}');
      onComplete({ targetProfile: profile, jobDescription: jd, persona });
    } catch (error) {
      console.error("Error generating persona:", error);
      // Fallback persona if AI fails
      onComplete({ 
        targetProfile: profile, 
        jobDescription: jd, 
        persona: {
          name: "Alex Rivera",
          role: "Senior Engineering Manager",
          background: "15 years in tech, former software architect at Google.",
          personality: "Direct, analytical, values brevity but appreciates well-researched questions.",
          company: "InnovateTech",
          voiceType: 'masculine'
        } 
      });
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto px-6 py-12">
      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm p-8 md:p-12">
        <h2 className="text-3xl font-bold text-slate-900 mb-2">Configure Your Simulation</h2>
        <p className="text-slate-500 mb-10">Paste the details of who you're networking with and the role you want.</p>

        <form onSubmit={handleSubmit} className="space-y-8">
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-3">
              LinkedIn Profile or Website Text
            </label>
            <textarea 
              value={profile}
              onChange={(e) => setProfile(e.target.value)}
              placeholder="Paste LinkedIn summary, experience details, or a link..."
              className="w-full h-32 p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
              required
            />
          </div>

          <div>
            <label className="block text-sm font-bold text-slate-700 mb-3">
              Target Job Description
            </label>
            <textarea 
              value={jd}
              onChange={(e) => setJd(e.target.value)}
              placeholder="Paste the job description you are targeting..."
              className="w-full h-32 p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
              required
            />
          </div>

          <div className="pt-4">
            <button 
              type="submit"
              disabled={isGenerating || !profile || !jd}
              className={`w-full py-4 rounded-xl font-bold text-white transition-all shadow-lg ${
                isGenerating ? 'bg-indigo-400 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700'
              }`}
            >
              {isGenerating ? (
                <span className="flex items-center justify-center">
                  <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Generating AI Persona...
                </span>
              ) : 'Ready Your Agent'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { SessionData, MessageLog, FeedbackData } from '../types';
import { Type } from "@google/genai";

interface SimulationProps {
  session: SessionData;
  onEnd: (messages: MessageLog[], feedback: FeedbackData) => void;
  onCancel: () => void;
}

export const Simulation: React.FC<SimulationProps> = ({ session, onEnd, onCancel }) => {
  const [isActive, setIsActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [messages, setMessages] = useState<MessageLog[]>([]);
  const [isEnding, setIsEnding] = useState(false);
  const [timer, setTimer] = useState(300); // 5 minutes

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const transcriptionRef = useRef({ user: '', model: '' });

  // Audio encoding/decoding helpers
  const encode = (bytes: Uint8Array) => {
    let binary = '';
    for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
    return btoa(binary);
  };
  const decode = (base64: string) => {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
    return bytes;
  };
  const decodeAudioData = async (data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number) => {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
    return buffer;
  };

  const startSimulation = async () => {
    setIsConnecting(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true, video: true });
      if (videoRef.current) videoRef.current.srcObject = stream;

      const inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const systemInstruction = `
        You are simulating a networking conversation. 
        Persona Name: ${session.persona?.name}
        Role: ${session.persona?.role} at ${session.persona?.company}
        Background: ${session.persona?.background}
        Personality Style: ${session.persona?.personality}
        Target Job Context: ${session.jobDescription}

        ${session.previousFeedback ? `The user is retrying this scenario. Previous feedback was: ${JSON.stringify(session.previousFeedback)}. Focus on challenging them on their weaknesses.` : ''}

        Rules:
        - MANDATORY START: You MUST initiate the conversation. Do not wait for the user to speak first.
        - Immediately introduce yourself as ${session.persona?.name} and mention your role.
        - Set a professional but welcoming tone. Say something like: "Hello! I'm ${session.persona?.name}, ${session.persona?.role}. I saw your request to connect regarding the ${session.jobDescription.split(' ').slice(0, 5).join(' ')}... context. Glad we could find a moment. What's on your mind?"
        - Act as this person naturally. 
        - Ask insightful follow-up questions.
        - Be realistic. If the pitch is poor, be politely skeptical.
        - Goal: Help the user practice until they are ready for a referral.
      `;

      // Determine voice name based on the generated persona's voiceType
      const voiceName = session.persona?.voiceType === 'feminine' ? 'Kore' : 'Puck';

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsActive(true);
            setIsConnecting(false);

            // Microphone stream
            const source = inputAudioContext.createMediaStreamSource(stream);
            const scriptProcessor = inputAudioContext.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000'
              };
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inputAudioContext.destination);

            // Frame stream (Visual context)
            const frameInterval = setInterval(() => {
              if (!videoRef.current || !canvasRef.current) return;
              const ctx = canvasRef.current.getContext('2d');
              if (!ctx) return;
              canvasRef.current.width = 320;
              canvasRef.current.height = 240;
              ctx.drawImage(videoRef.current, 0, 0, 320, 240);
              canvasRef.current.toBlob(blob => {
                if (blob) {
                  const reader = new FileReader();
                  reader.onloadend = () => {
                    const base64 = (reader.result as string).split(',')[1];
                    sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'image/jpeg' } }));
                  };
                  reader.readAsDataURL(blob);
                }
              }, 'image/jpeg', 0.5);
            }, 1000);
            (sessionRef as any).currentInterval = frameInterval;

            // CRITICAL: Trigger the model to introduce itself first
            sessionPromise.then(s => {
              s.sendRealtimeInput({ 
                text: "The user has joined the meeting. Please start the conversation by introducing yourself and welcoming the user." 
              });
            });
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle audio output
            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && outputAudioContextRef.current) {
              const buffer = await decodeAudioData(decode(audioData), outputAudioContextRef.current, 24000, 1);
              const source = outputAudioContextRef.current.createBufferSource();
              source.buffer = buffer;
              source.connect(outputAudioContextRef.current.destination);
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioContextRef.current.currentTime);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              source.onended = () => sourcesRef.current.delete(source);
            }

            // Handle Transcriptions for feedback step
            if (message.serverContent?.inputTranscription) {
              transcriptionRef.current.user += message.serverContent.inputTranscription.text + " ";
            }
            if (message.serverContent?.outputTranscription) {
              transcriptionRef.current.model += message.serverContent.outputTranscription.text + " ";
            }
            if (message.serverContent?.turnComplete) {
              const uText = transcriptionRef.current.user.trim();
              const mText = transcriptionRef.current.model.trim();
              if (uText || mText) {
                setMessages(prev => [
                  ...prev,
                  { role: 'user', text: uText || "(Silent Listening)" },
                  { role: 'model', text: mText }
                ]);
              }
              transcriptionRef.current = { user: '', model: '' };
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e) => console.error("Session Error:", e),
          onclose: () => setIsActive(false),
        },
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction,
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName } } },
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error(err);
      setIsConnecting(false);
    }
  };

  useEffect(() => {
    let interval: any;
    if (isActive && timer > 0) {
      interval = setInterval(() => setTimer(t => t - 1), 1000);
    } else if (timer === 0 && isActive) {
      endSession();
    }
    return () => clearInterval(interval);
  }, [isActive, timer]);

  const endSession = async () => {
    if (isEnding) return;
    setIsEnding(true);

    // Stop recording/streaming
    if (sessionRef.current) {
      if ((sessionRef as any).currentInterval) clearInterval((sessionRef as any).currentInterval);
      sessionRef.current.close();
    }

    // Process final feedback using Gemini Chat
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const conversationText = messages.map(m => `${m.role}: ${m.text}`).join('\n');

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Evaluate this networking simulation for a job seeker. 
          Target Role: ${session.persona?.role}
          Job: ${session.jobDescription}
          Conversation:
          ${conversationText}`,
        config: {
          responseMimeType: 'application/json',
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              score: { type: Type.NUMBER, description: 'Score from 0 to 100' },
              strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
              weaknesses: { type: Type.ARRAY, items: { type: Type.STRING } },
              suggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
              conversationSummary: { type: Type.STRING },
              difficultyAdjustment: { type: Type.STRING, description: 'How to adjust difficulty for next time' }
            },
            required: ['score', 'strengths', 'weaknesses', 'suggestions', 'conversationSummary', 'difficultyAdjustment']
          }
        }
      });

      const feedback: FeedbackData = JSON.parse(response.text || '{}');
      onEnd(messages, feedback);
    } catch (err) {
      console.error("Failed to generate feedback:", err);
      // Fallback feedback
      onEnd(messages, {
        score: 75,
        strengths: ["Clear opening pitch", "Good enthusiasm"],
        weaknesses: ["Too focused on self", "Lack of research on company"],
        suggestions: ["Ask more about the persona's recent work", "Keep answers under 60 seconds"],
        conversationSummary: "You had a standard interaction but failed to bridge to a referral request.",
        difficultyAdjustment: "Increase skepticisms of the persona"
      });
    }
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  // Dedicated loading UI for the feedback generation phase
  if (isEnding) {
    return (
      <div className="fixed inset-0 bg-slate-900 z-[100] flex flex-col items-center justify-center">
        <div className="text-center p-8 max-w-xl">
          <div className="relative w-24 h-24 mx-auto mb-8">
            <div className="absolute inset-0 border-4 border-indigo-500/20 rounded-full"></div>
            <div className="absolute inset-0 border-4 border-indigo-500 rounded-full border-t-transparent animate-spin"></div>
          </div>
          <h2 className="text-3xl font-bold text-white mb-4">Generating Session Review</h2>
          <p className="text-slate-400">
            Analyzing your conversation with <strong>{session.persona?.name}</strong>...<br/>
            Evaluating clarity, confidence, and impact.
          </p>
          <div className="mt-8 flex justify-center space-x-2">
            <div className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce"></div>
            <div className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce delay-100"></div>
            <div className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce delay-200"></div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 bg-slate-900 z-[100] flex flex-col items-center justify-center overflow-hidden">
      {!isActive && !isConnecting && (
        <div className="text-center p-8 max-w-xl">
          <h2 className="text-3xl font-bold text-white mb-6">Simulation Ready</h2>
          <p className="text-slate-400 mb-10">
            You will be speaking with <strong>{session.persona?.name}</strong>. 
            Once you enter, <strong>they will introduce themselves first</strong>. Listen carefully and then respond with your pitch.
          </p>
          <div className="flex space-x-4 justify-center">
            <button 
              onClick={startSimulation}
              className="px-10 py-4 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl shadow-xl transition-all"
            >
              Enter Room
            </button>
            <button 
              onClick={onCancel}
              className="px-10 py-4 bg-slate-800 hover:bg-slate-700 text-white font-bold rounded-xl transition-all"
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      {(isActive || isConnecting) && (
        <div className="w-full h-full flex flex-col">
          {/* Header Info */}
          <div className="p-6 flex justify-between items-center text-white bg-slate-900/50 backdrop-blur-md">
            <div className="flex items-center space-x-4">
              <div className="w-12 h-12 rounded-full overflow-hidden border-2 border-indigo-500">
                <img src={`https://picsum.photos/seed/${session.persona?.name}/48/48`} alt="Persona" />
              </div>
              <div>
                <h3 className="font-bold text-lg">{session.persona?.name}</h3>
                <p className="text-xs text-slate-400 uppercase tracking-widest">{session.persona?.role}</p>
              </div>
            </div>
            <div className="flex items-center space-x-6">
              <div className="text-center">
                <p className="text-xs text-slate-500 uppercase font-bold">Time Left</p>
                <p className={`text-xl font-mono ${timer < 60 ? 'text-red-500 animate-pulse' : 'text-white'}`}>{formatTime(timer)}</p>
              </div>
              <button 
                onClick={endSession}
                className="px-6 py-2 bg-red-600 hover:bg-red-700 text-white font-bold rounded-lg transition-all"
                disabled={isEnding}
              >
                End Session
              </button>
            </div>
          </div>

          {/* Main Visual Area */}
          <div className="flex-grow flex flex-col md:flex-row p-6 gap-6 relative">
            {/* The "Persona" Card */}
            <div className="flex-grow bg-slate-800 rounded-3xl overflow-hidden border border-slate-700 flex flex-col items-center justify-center relative shadow-2xl">
              <div className="absolute inset-0 opacity-20 pointer-events-none">
                <div className="w-full h-full bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-indigo-500/20 via-transparent to-transparent animate-pulse"></div>
              </div>

              <div className="z-10 text-center">
                <div className="w-32 h-32 rounded-full bg-slate-700 mx-auto mb-6 flex items-center justify-center border-4 border-indigo-500/30 overflow-hidden">
                   {isActive ? (
                     <div className="flex space-x-1 items-end h-8">
                       {[1, 2, 3, 4, 5].map(i => (
                         <div key={i} className={`w-1.5 bg-indigo-400 rounded-full animate-bounce`} style={{ animationDelay: `${i * 0.1}s`, height: `${Math.random() * 100 + 20}%` }}></div>
                       ))}
                     </div>
                   ) : (
                     <div className="text-slate-500">Connecting...</div>
                   )}
                </div>
                <h2 className="text-2xl font-bold text-white mb-2">
                  {isConnecting ? 'Establishing Connection...' : `${session.persona?.name} is Speaking...`}
                </h2>
                <p className="text-indigo-400 font-medium">Listen to the introduction</p>
              </div>
            </div>

            {/* Camera Feed (User) */}
            <div className="w-full md:w-80 h-60 md:h-auto bg-black rounded-3xl overflow-hidden border border-slate-700 shadow-2xl relative">
              <video 
                ref={videoRef} 
                autoPlay 
                muted 
                playsInline 
                className="w-full h-full object-cover mirror"
              />
              <canvas ref={canvasRef} className="hidden" />
              <div className="absolute bottom-4 left-4 right-4 bg-black/40 backdrop-blur-sm p-3 rounded-xl border border-white/10">
                <div className="flex items-center space-x-2">
                  <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
                  <span className="text-xs text-white font-bold uppercase">Microphone Active</span>
                </div>
              </div>
            </div>
          </div>

          {/* Chat Preview footer */}
          <div className="h-24 bg-slate-800/80 border-t border-slate-700 p-4 flex items-center justify-center">
            <div className="max-w-2xl w-full text-center">
               <p className="text-slate-400 italic text-sm">
                 {messages.length > 0 ? messages[messages.length - 1].text.substring(0, 100) + "..." : "Transcribing interaction..."}
               </p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};
